import React, { useState } from 'react'; 
import '../styles/Register.css';
import { Link, useNavigate } from 'react-router-dom'; // Added useNavigate for redirection

function Login() {
  // 1. Create state for the input fields
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  
  const navigate = useNavigate();

  const handleLogin = (e) => {
    e.preventDefault(); // Prevents the page from refreshing
    setError('');

    // 2. Simple Frontend Validation
    if (!email || !password) {
      setError('Please fill in all fields');
      return;
    }

    // 3. Simulate an API Call
    // In a real app, you'd send this to your backend
    if (email === "user@hirehub.com" && password === "password123") {
      
      // 4. Set the "Gate" (Session Management)
      localStorage.setItem('userToken', 'secure-jwt-string');
      
      // 5. Redirect to the Find Jobs page
      navigate('/find-jobs');
    } else {
      setError('Invalid email or password. Try user@hirehub.com');
    }
  };
    return (
        <div className="auth-wrapper">
            <div className="auth-card">
                <div className="auth-header">
                    <h2>Sign in</h2>
                </div>
                <form className="auth-form" onSubmit={handleSubmit}>
                    <div className="input-group">
                        <label>Email Address</label>
                        <input 
                            type="email" 
                            name="email" // Added name to match state key
                            placeholder="example@pau.edu.ng" 
                            value={loginData.email}
                            onChange={handleChange}
                            required 
                        />
                    </div>
                    <div className="input-group">
                        <label>Password</label>
                        <input 
                            type="password" 
                            name="password" // Added name to match state key
                            placeholder="Enter password" 
                            value={loginData.password}
                            onChange={handleChange}
                            required 
                        />
                    </div>
                    <button type="submit" className="auth-btn">Login</button>
                </form>
                <div className="auth-footer">
                    <p>Don't have an account? <Link to="/register">Create an account</Link></p>
                </div>
            </div>
        </div>
    );
};

export default Login;
